const items = $input.all().map(i => i.json);
const enriched = items.map(item => ({
  ...item,
  _should_promote: item.sync_status === 'stage_mismatch' && !!item.opp_id && !!item.expected_opp_stage,
  _is_orphaned: item.sync_status === 'orphaned_plan',
  _sync_note: item.sync_status === 'stage_mismatch'
    ? `Gate ${item.gate_stage} to opp should be ${item.expected_opp_stage} but is ${item.opp_stage}`
    : item.sync_status === 'orphaned_plan'
    ? `Capture plan ${item.plan_opp_name} has no linked opp`
    : 'other'
}));
return enriched.map(e => ({json: e}));

